export const getListListingAttributeOptionsUrl = (categoryId: number,
    params?: ListListingAttributeOptionsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/categories/${categoryId}/listing-attribute-options?${stringifiedParams}` : `/api/categories/${categoryId}/listing-attribute-options`
}

